INSERT INTO academy_courses (slug, title, track, description, image, instructor, duration_weeks, schedule, branch_slug, delivery_format, fee, deposit_required, available_seats, modules, certificate_awarded) VALUES
('beginner-nigerian-cooking', 'Beginner Nigerian Cooking', 'cooking', 'Master the fundamentals of Nigerian cuisine — soups, rice dishes and swallow — from scratch.', '/images/academy/beginner-nigerian-cooking.jpg', 'Chef Ngozi Adeyemi', 4, 'Saturdays, 10am–1pm', 'lagos', 'in-person', 65000, 20000, 12, ARRAY['Knife skills & prep','Soups & stews','Rice dishes','Swallow techniques'], true),
('advanced-continental-cuisine', 'Advanced Continental Cuisine', 'cooking', 'Take your skills further with continental techniques, plating and sauce work.', '/images/academy/advanced-continental-cuisine.jpg', 'Chef David Okafor', 6, 'Weekday evenings, 6pm–8pm', 'abuja', 'in-person', 95000, 30000, 10, ARRAY['Sauce fundamentals','Protein cookery','Plating & presentation','Menu design'], true),
('small-chops-party-snacks', 'Small Chops & Party Snacks', 'cooking', 'Learn to make small chops, spring rolls and party snacks for events and side businesses.', '/images/academy/small-chops-party-snacks.jpg', 'Chef Amaka Nwosu', 2, 'Weekend intensive', 'lagos', 'in-person', 45000, 15000, 15, ARRAY['Batter & dough basics','Frying techniques','Packaging for events'], true),
('baking-fundamentals', 'Baking Fundamentals', 'baking', 'Build a strong foundation in baking — bread, pastries and simple cakes.', '/images/academy/baking-fundamentals.jpg', 'Chef Fatima Sani', 4, 'Saturdays, 2pm–5pm', 'abuja', 'in-person', 70000, 20000, 12, ARRAY['Bread basics','Pastry dough','Simple sponge cakes','Kitchen hygiene'], true),
('professional-cake-decoration', 'Professional Cake Decoration', 'baking', 'Advanced fondant, buttercream and sugar-flower techniques for celebration cakes.', '/images/academy/professional-cake-decoration.jpg', 'Chef Peace Effiong', 6, 'Weekday mornings, 9am–12pm', 'lagos', 'hybrid', 120000, 40000, 8, ARRAY['Fondant covering','Buttercream piping','Sugar flowers','Wedding cake tiers'], true),
('catering-business-management', 'Catering Business Management', 'cooking', 'A practical course for turning your cooking skills into a catering business.', '/images/academy/catering-business-management.jpg', 'Chef Emeka Nnamdi', 3, 'Online, self-paced with live Q&A', 'lagos', 'online', 55000, 15000, 20, ARRAY['Costing & pricing','Client management','Event logistics','Food safety compliance'], false);
